function randomFailWand() {
  // Fails can be any combo, not restricted to the 17-wand pool
  const WOODS = ["Acacia","Alder","Apple","Ash","Aspen","Beech","Blackthorn","Black Walnut","Cedar","Cherry","Chestnut","Cypress","Dogwood","Ebony","Elder","Elm","English Oak","Fir","Hawthorn","Hazel","Holly","Hornbeam","Larch","Laurel","Maple","Pear","Pine","Poplar","Red Oak","Redwood","Rowan","Silver Lime","Spruce","Sycamore","Vine","Walnut","Willow","Yew"];
  const CORES = ["Unicorn Hair","Phoenix Feather","Dragon Heartstring"];
  const LENGTHS = ['9"',"9¼\"","9½\"","9¾\"",'10"',"10¼\"","10½\"","10¾\"",'11"',"11¼\"","11½\"","11¾\"",'12"',"12¼\"","12½\"","12¾\"",'13"',"13¼\"","13½\"","13¾\"",'14"'];
  const FLEX = ["Bendy","Brittle","Firm","Hard","Inflexible","Pliant","Reasonably Supple","Rigid","Slightly Bendy","Slightly Springy","Solid","Springy","Stiff","Supple","Swishy","Unbending","Unyielding","Very Flexible","Whippy"];
  return {
    wood: WOODS[Math.floor(Math.random()*WOODS.length)],
    core: CORES[Math.floor(Math.random()*CORES.length)],
    length: LENGTHS[Math.floor(Math.random()*LENGTHS.length)],
    flex: FLEX[Math.floor(Math.random()*FLEX.length)],
  };
}

// ── Sparks ───────────────────────────────────────────────────────────────
function Sparks({ type, active }) {
  const ref = useRef(null);
  const animRef = useRef(null);
  useEffect(() => {
    cancelAnimationFrame(animRef.current);
    if (!active) {
      const canvas = ref.current;
      if (canvas) canvas.getContext("2d").clearRect(0,0,canvas.width,canvas.height);
      return;
    }
    const canvas = ref.current; if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width, H = canvas.height;
    const c1 = type==="fail"?"#ff3333":"#00ee77";
    const c2 = type==="fail"?"#ff8800":"#aaffcc";
    const pts = Array.from({length:70},()=>({
      x:W/2+(Math.random()-.5)*80, y:H/2+(Math.random()-.5)*40,
      vx:(Math.random()-.5)*9, vy:(Math.random()-.5)*9-2,
      life:.5+Math.random()*.5, sz:1+Math.random()*3,
    }));
    function frame() {
      ctx.clearRect(0,0,W,H); let alive=false;
      pts.forEach(p=>{
        p.x+=p.vx; p.y+=p.vy; p.vy+=0.18; p.life-=0.02;
        if(p.life>0){ alive=true;
          ctx.save(); ctx.globalAlpha=Math.min(p.life*2,1);
          ctx.shadowColor=c1; ctx.shadowBlur=10;
          ctx.fillStyle=Math.random()>.5?c1:c2;
          ctx.beginPath(); ctx.arc(p.x,p.y,p.sz*p.life,0,Math.PI*2); ctx.fill();
          ctx.restore();
        }
      });
      if(alive) animRef.current=requestAnimationFrame(frame);
      else ctx.clearRect(0,0,W,H);
    }
    animRef.current=requestAnimationFrame(frame);
    return ()=>cancelAnimationFrame(animRef.current);
  }, [active, type]);
  return <canvas ref={ref} width={320} height={200} style={{position:"absolute",top:0,left:0,pointerEvents:"none",width:"100%",height:"100%"}}/>;
}

// ── Audio ─────────────────────────────────────────────────────────────────
function playFail(a){
  const o=a.createOscillator(),g=a.createGain();
  o.connect(g);g.connect(a.destination);
  o.frequency.setValueAtTime(220,a.currentTime);
  o.frequency.exponentialRampToValueAtTime(60,a.currentTime+0.5);
  g.gain.setValueAtTime(0.3,a.currentTime);g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.6);
  o.start();o.stop(a.currentTime+0.6);
  const o2=a.createOscillator(),g2=a.createGain();
  o2.type="sawtooth";o2.connect(g2);g2.connect(a.destination);
  o2.frequency.setValueAtTime(140,a.currentTime+0.1);o2.frequency.exponentialRampToValueAtTime(55,a.currentTime+0.6);
  g2.gain.setValueAtTime(0.18,a.currentTime+0.1);g2.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.7);
  o2.start(a.currentTime+0.1);o2.stop(a.currentTime+0.7);
}
function playSuccess(a){
  [523.25,659.25,783.99,1046.5].forEach((freq,i)=>{
    const o=a.createOscillator(),g=a.createGain();
    o.type="sine";o.connect(g);g.connect(a.destination);
    const t=a.currentTime+i*0.18;
    o.frequency.setValueAtTime(freq,t);
    g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(0.25,t+0.05);
    g.gain.exponentialRampToValueAtTime(0.001,t+0.8);
    o.start(t);o.stop(t+0.9);
  });
}

// ── Parchment Label with Wand Number ────────────────────────────────────
function ParchmentLabel({ wand, name, hideNumber }) {
  const img = getWandImage(wand.wood, wand.core);
  const glow = CORE_GLOW[wand.core];
  return (
    <div style={{background:"linear-gradient(135deg,#f5e6c8 0%,#eddcaa 30%,#e8d090 60%,#f0e0b0 100%)",border:"3px solid #8b6914",borderRadius:"4px",padding:"28px 24px",maxWidth:360,margin:"0 auto",boxShadow:"0 0 40px rgba(255,200,80,0.2),inset 0 0 30px rgba(139,105,20,0.1)",position:"relative",fontFamily:"'Palatino Linotype',Palatino,serif"}}>
      {/* Wand number badge - collector card style */}
      {!hideNumber && (
        <div style={{position:"absolute",top:-14,left:"50%",transform:"translateX(-50%)",background:"linear-gradient(135deg,#6a0dad,#4a0080)",border:"2px solid #d4a843",borderRadius:"50%",width:44,height:44,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 2px 10px rgba(0,0,0,0.4)",zIndex:2}}>
          <span style={{color:"#fff",fontWeight:"bold",fontSize:16,textShadow:"0 0 6px rgba(212,168,67,0.8)"}}>#{wand.id}</span>
        </div>
      )}
      {["top:8px;left:8px","top:8px;right:8px","bottom:8px;left:8px","bottom:8px;right:8px"].map((pos,i)=>(
        <div key={i} style={{position:"absolute",...Object.fromEntries(pos.split(";").map(p=>p.split(":"))),fontSize:16,color:"#8b6914",opacity:0.7}}>✦</div>
      ))}
      <div style={{textAlign:"center",borderBottom:"1px solid #8b6914",paddingBottom:10,marginBottom:14,marginTop:10}}>
        <div style={{fontSize:11,letterSpacing:4,color:"#5a3e0a",textTransform:"uppercase",marginBottom:3}}>Ollivanders</div>
        <div style={{fontSize:9,letterSpacing:2,color:"#7a5a1a",fontStyle:"italic"}}>Makers of Fine Wands since 382 B.C.</div>
      </div>
      <div style={{textAlign:"center",marginBottom:14,borderRadius:6,overflow:"hidden",border:"1px solid rgba(139,105,20,0.2)"}}>
        {img && <img src={img} alt={wand.wood} style={{width:"100%",display:"block"}}/>}
      </div>
      <div style={{textAlign:"center",marginBottom:14}}>
        <div style={{fontSize:12,color:"#5a3e0a",letterSpacing:1,marginBottom:3}}>Presented to</div>
        <div style={{fontSize:20,color:"#2a1a05",fontWeight:"bold",letterSpacing:1}}>{name}</div>
      </div>
      <div style={{borderTop:"1px solid #8b6914",paddingTop:12,display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px"}}>
        {[["Wood",wand.wood],["Core",wand.core],["Length",wand.length],["Flexibility",wand.flex]].map(([lbl,val])=>(
          <div key={lbl}>
            <div style={{fontSize:8,letterSpacing:2,color:"#7a5a1a",textTransform:"uppercase",marginBottom:2}}>{lbl}</div>
            <div style={{fontSize:13,color:"#2a1a05",fontWeight:"600"}}>{val}</div>
          </div>
        ))}
      </div>
      <div style={{textAlign:"center",marginTop:14,fontSize:9,color:"#7a5a1a",fontStyle:"italic"}}>— The wand chooses the wizard —</div>
    </div>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────
export default function App() {
  const [screen, setScreen]             = useState("select");   // select | generator | success | label
  const [remainingKids, setRemainingKids] = useState(KIDS);
  const [completedKids, setCompletedKids] = useState([]);
  const [wandPool, setWandPool]         = useState(PARTY_WANDS.map(w=>({...w, allocated:false, allocatedTo:null})));
  const [currentName, setCurrentName]   = useState(null);
  const [currentWand, setCurrentWand]   = useState(null);
  const [finalWand, setFinalWand]       = useState(null);
  const [failCount, setFailCount]       = useState(0);
  const [maxFails, setMaxFails]         = useState(0);
  const [sparksActive, setSparksActive] = useState(false);
  const [sparksType, setSparksType]     = useState("fail");
  const [isAnimating, setIsAnimating]   = useState(false);
  const [showWand, setShowWand]         = useState(false);
  const [freePlay, setFreePlay]         = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [freeFirstName, setFreeFirstName] = useState("");
  const [freeLastName, setFreeLastName] = useState("");
  const audioRef = useRef(null);

  const getACtx = () => {
    if (!audioRef.current) audioRef.current = new (window.AudioContext||window.webkitAudioContext)();
    return audioRef.current;
  };

  const triggerSparks = useCallback((type,cb)=>{
    setSparksType(type); setSparksActive(true);
    const a=getACtx();
    if(type==="fail") playFail(a); else playSuccess(a);
    setTimeout(()=>{ setSparksActive(false); cb&&cb(); },1800);
  },[]);

  function getAvailablePool(forName) {
    // Reserved wand only available for the reserved name
    return wandPool.filter(w => {
      if (w.allocated) return false;
      if (w.id === RESERVED_WAND_ID && forName !== RESERVED_FOR_NAME) return false;
      return true;
    });
  }

  function pickFinalWandFor(name) {
    // If this is the reserved child, guarantee the reserved wand if still available
    if (name === RESERVED_FOR_NAME) {
      const reserved = wandPool.find(w => w.id === RESERVED_WAND_ID && !w.allocated);
      if (reserved) return reserved;
    }
    const pool = getAvailablePool(name);
    if (pool.length === 0) return null;
    return pool[Math.floor(Math.random()*pool.length)];
  }

  function startMatch(name) {
    if (completedKids.includes(name)) return; // already matched, safety guard
    const fw = pickFinalWandFor(name);
    if (!fw) { alert("No wands left in the pool!"); return; }
    setCurrentName(name);
    setFinalWand(fw);
    const fails = 1+Math.floor(Math.random()*3);
    setMaxFails(fails+1); setFailCount(1);
    setCurrentWand(randomFailWand());
    setShowWand(false); setScreen("generator"); setIsAnimating(true);
    setTimeout(()=>{ setShowWand(true); setIsAnimating(false); triggerSparks("fail"); },800);
  }

  function tryAgain() {
    if (isAnimating) return;
    setFailCount(c=>c+1); setShowWand(false); setIsAnimating(true);
    setTimeout(()=>{ setCurrentWand(randomFailWand()); setShowWand(true); setIsAnimating(false); triggerSparks("fail"); },600);
  }

  function tryFinalWand() {
    if (isAnimating) return;
    setShowWand(false); setIsAnimating(true);
    setTimeout(()=>{
      setCurrentWand(finalWand); setShowWand(true); setIsAnimating(false);
      setScreen("success"); triggerSparks("success");
    },800);
  }

  function confirmPurchase() {
    // Lock the wand
    setWandPool(pool => pool.map(w => w.id===finalWand.id ? {...w, allocated:true, allocatedTo:currentName} : w));
    // Mark kid as completed (if not free play) but keep them visible with a checkmark
    if (!freePlay && currentName !== "Guest") {
      setCompletedKids(list => [...list, currentName]);
    }
    setScreen("label");
  }

  function backToSelect() {
    setScreen("select");
    setCurrentName(null); setCurrentWand(null); setFinalWand(null);
    setShowWand(false);
  }

  function resetParty() {
    setWandPool(PARTY_WANDS.map(w=>({...w, allocated:false, allocatedTo:null})));
    setRemainingKids(KIDS);
    setCompletedKids([]);
    setFreePlay(false);
    setCurrentName(null); setCurrentWand(null); setFinalWand(null);
    setShowWand(false); setScreen("select"); setShowResetConfirm(false);
  }

  const isFinalFail = failCount >= maxFails;
  const wandImg = currentWand ? getWandImage(currentWand.wood, currentWand.core) : null;
  const glow = currentWand ? CORE_GLOW[currentWand.core] : "#b388ff";
  const wandsLeft = wandPool.filter(w=>!w.allocated).length;
  const availableForFreePlay = wandPool.filter(w=>!w.allocated && w.id!==RESERVED_WAND_ID || (w.id===RESERVED_WAND_ID && !w.allocated && remainingKids.includes(RESERVED_FOR_NAME)===false && false));

  const S = {
    app:{ minHeight:"100vh", background:"radial-gradient(ellipse at 50% 0%,#1a0a2e 0%,#0d0618 40%,#080410 100%)", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", fontFamily:"'Palatino Linotype',Palatino,Georgia,serif", padding:"20px", position:"relative", overflow:"hidden" },
    stars:{ position:"fixed",inset:0,pointerEvents:"none",zIndex:0,background:"radial-gradient(1px 1px at 20% 30%,rgba(255,255,255,0.4) 0%,transparent 100%),radial-gradient(1px 1px at 80% 10%,rgba(255,255,255,0.3) 0%,transparent 100%),radial-gradient(1px 1px at 50% 60%,rgba(255,255,255,0.2) 0%,transparent 100%),radial-gradient(1px 1px at 10% 80%,rgba(255,255,255,0.3) 0%,transparent 100%)" },
    card:{ background:"linear-gradient(160deg,rgba(30,10,60,0.95) 0%,rgba(15,5,30,0.98) 100%)", border:"1px solid rgba(150,80,255,0.25)", borderRadius:"8px", padding:"32px 30px", maxWidth:480, width:"100%", position:"relative", zIndex:1, boxShadow:"0 0 60px rgba(100,0,200,0.2),0 20px 60px rgba(0,0,0,0.6),inset 0 1px 0 rgba(150,80,255,0.15)" },
    title:{ textAlign:"center",color:"#d4a843",fontSize:26,letterSpacing:5,textTransform:"uppercase",marginBottom:4,textShadow:"0 0 20px rgba(212,168,67,0.5)" },
    subtitle:{ textAlign:"center",color:"rgba(180,130,255,0.6)",fontSize:11,letterSpacing:3,marginBottom:20,fontStyle:"italic" },
    input:{ width:"100%",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(150,80,255,0.3)",borderRadius:"4px",padding:"12px 16px",color:"#e8d5ff",fontSize:15,fontFamily:"inherit",outline:"none",marginBottom:10,boxSizing:"border-box" },
    btn:{ width:"100%",padding:"14px",background:"linear-gradient(135deg,#6a0dad 0%,#4a0080 100%)",border:"1px solid rgba(180,100,255,0.5)",borderRadius:"4px",color:"#e8d5ff",fontSize:14,letterSpacing:2,textTransform:"uppercase",cursor:"pointer",fontFamily:"inherit",marginTop:8,textShadow:"0 0 10px rgba(200,150,255,0.5)",boxShadow:"0 0 20px rgba(100,0,200,0.3)" },
    btnGreen:{ background:"linear-gradient(135deg,#0a5c2a 0%,#064a1e 100%)",border:"1px solid rgba(100,255,150,0.5)",color:"#a0ffcc",textShadow:"0 0 10px rgba(100,255,150,0.5)",boxShadow:"0 0 20px rgba(0,200,80,0.3)" },
    nameBtn:{ width:"100%",padding:"13px 16px",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(150,80,255,0.25)",borderRadius:"4px",color:"#e8d5ff",fontSize:14,cursor:"pointer",fontFamily:"inherit",marginBottom:8,textAlign:"left",transition:"all 0.2s" },
    wandBox:{ position:"relative",borderRadius:"6px",overflow:"hidden",marginBottom:18,background:"#f8f3e9",border:"2px solid rgba(139,105,20,0.25)" },
    grid:{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 16px",marginTop:14 },
    stat:{ background:"rgba(255,255,255,0.03)",border:"1px solid rgba(150,80,255,0.15)",borderRadius:"4px",padding:"10px 12px" },
    sLbl:{ fontSize:9,letterSpacing:2,color:"rgba(180,130,255,0.5)",textTransform:"uppercase",marginBottom:3 },
    sVal:{ fontSize:14,color:"#e8d5ff",fontWeight:"600" },
    badge:(ok)=>({ display:"inline-block",padding:"4px 14px",borderRadius:20,fontSize:11,letterSpacing:2,textTransform:"uppercase",marginBottom:10,background:ok?"rgba(0,200,80,0.15)":"rgba(255,50,50,0.15)",border:`1px solid ${ok?"rgba(0,200,80,0.4)":"rgba(255,50,50,0.4)"}`,color:ok?"#80ffaa":"#ff8888" }),
  };

  return (
    <div style={S.app}>
      <div style={S.stars}/>

      {/* SELECT NAME / FREE PLAY SCREEN */}
      {screen==="select" && (
        <div style={S.card}>
          <div style={{textAlign:"center",fontSize:34,marginBottom:6}}>🪄</div>
          <div style={S.title}>Ollivanders</div>
          <div style={S.subtitle}>{freePlay ? "Free Play — Remaining Wands" : "Select the Next Wizard"}</div>

          <div style={{textAlign:"center",marginBottom:16,fontSize:11,color:"rgba(180,130,255,0.5)",letterSpacing:1}}>
            {wandsLeft} of 17 wands remaining
          </div>

          {!freePlay && (
            <>
              <div style={{maxHeight:320,overflowY:"auto",marginBottom:12}}>
                {remainingKids.map(name => {
                  const done = completedKids.includes(name);
                  return (
                    <button key={name} style={{...S.nameBtn, opacity:done?0.5:1, cursor:done?"default":"pointer", display:"flex", justifyContent:"space-between", alignItems:"center"}}
                      onClick={()=>!done && startMatch(name)}>
                      <span>{name}</span>
                      {done && <span style={{color:"#80ffaa",fontSize:16}}>✓</span>}
                    </button>
                  );
                })}
              </div>
              <div style={{textAlign:"center",fontSize:11,color:"rgba(180,130,255,0.5)",marginBottom:10}}>
                {completedKids.length} of {remainingKids.length} wizards matched
              </div>
              <button style={{...S.btn,background:"linear-gradient(135deg,#0a5c2a 0%,#064a1e 100%)",border:"1px solid rgba(100,255,150,0.5)",color:"#a0ffcc",textShadow:"0 0 10px rgba(100,255,150,0.5)",boxShadow:"0 0 20px rgba(0,200,80,0.3)"}}
                onClick={()=>setFreePlay(true)}>
                🎉 Everyone's Here — Start Free Play
              </button>
            </>
          )}

          {freePlay && (
            <div style={{marginBottom:16}}>
              <p style={{color:"rgba(200,170,255,0.7)",fontSize:12,lineHeight:1.7,fontStyle:"italic",marginBottom:16,textAlign:"center"}}>
                Free play is active! Enter your name to try your luck with a remaining wand.
              </p>
              <input style={S.input} placeholder="First Name" value={freeFirstName} onChange={e=>setFreeFirstName(e.target.value)}/>
              <input style={S.input} placeholder="Surname" value={freeLastName} onChange={e=>setFreeLastName(e.target.value)}/>
              <button style={{...S.btn,opacity:(freeFirstName.trim()&&freeLastName.trim()&&wandsLeft>0)?1:0.5}}
                onClick={()=>{
                  const full = `${freeFirstName.trim()} ${freeLastName.trim()}`;
                  startMatch(full);
                  setFreeFirstName(""); setFreeLastName("");
                }}
                disabled={!freeFirstName.trim()||!freeLastName.trim()||wandsLeft===0}>
                {wandsLeft>0 ? "🪄 Find My Wand" : "No Wands Left"}
              </button>
              <button style={{...S.btn,marginTop:8,fontSize:11,background:"rgba(255,255,255,0.03)",boxShadow:"none",textShadow:"none"}}
                onClick={()=>setFreePlay(false)}>
                ← Back to Named List
              </button>
            </div>
          )}

          <button style={{...S.btn,marginTop:16,fontSize:11,background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,80,80,0.3)",color:"rgba(255,150,150,0.8)",boxShadow:"none",textShadow:"none"}}
            onClick={()=>setShowResetConfirm(true)}>
            🔄 Reset Entire Party
          </button>

          {showResetConfirm && (
            <div style={{marginTop:14,padding:14,background:"rgba(255,50,50,0.08)",border:"1px solid rgba(255,80,80,0.3)",borderRadius:6,textAlign:"center"}}>
              <p style={{color:"#ffb0b0",fontSize:12,marginBottom:10}}>This will clear all wand allocations and restore all 17 wands and 14 names. Are you sure?</p>
              <div style={{display:"flex",gap:8}}>
                <button style={{...S.btn,marginTop:0,background:"rgba(255,50,50,0.3)",border:"1px solid rgba(255,80,80,0.5)"}} onClick={resetParty}>Yes, Reset</button>
                <button style={{...S.btn,marginTop:0}} onClick={()=>setShowResetConfirm(false)}>Cancel</button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* GENERATOR + SUCCESS */}
      {(screen==="generator"||screen==="success") && currentWand && (
        <div style={S.card}>
          <div style={{textAlign:"center",marginBottom:14}}>
            <div style={{fontSize:12,letterSpacing:3,color:"rgba(180,130,255,0.5)",textTransform:"uppercase"}}>{currentName}</div>
            <div style={{fontSize:9,color:"rgba(150,100,220,0.4)",letterSpacing:2,marginTop:3}}>Ollivanders · Diagon Alley</div>
          </div>
          <div style={S.wandBox}>
            <Sparks type={sparksType} active={sparksActive}/>
            {showWand&&!isAnimating&&(
              <div style={{animation:"fadeIn .5s ease"}}>
                {wandImg
                  ? <img src={wandImg} alt="wand" style={{width:"100%",display:"block",filter:`drop-shadow(0 0 8px ${glow}88)`}}/>
                  : <div style={{padding:60,textAlign:"center",color:"rgba(100,70,150,0.4)",fontSize:30}}>🪄</div>
                }
              </div>
            )}
            {isAnimating&&<div style={{color:"rgba(100,70,150,0.5)",fontSize:13,letterSpacing:2,padding:"60px 0",textAlign:"center",fontStyle:"italic",background:"#f8f3e9"}}>Selecting wand…</div>}
          </div>
          {showWand&&!isAnimating&&(
            <>
              <div style={{textAlign:"center"}}>
                <span style={S.badge(screen==="success")}>{screen==="success"?"✦ Perfect Match ✦":"✗ No Match"}</span>
                {screen==="success" && finalWand && !freePlay && (
                  <div style={{marginTop:4}}>
                    <span style={{display:"inline-block",background:"linear-gradient(135deg,#6a0dad,#4a0080)",border:"2px solid #d4a843",borderRadius:20,padding:"4px 16px",color:"#fff",fontWeight:"bold",fontSize:15,textShadow:"0 0 6px rgba(212,168,67,0.8)",boxShadow:"0 2px 8px rgba(0,0,0,0.4)"}}>
                      Wand #{finalWand.id}
                    </span>
                  </div>
                )}
              </div>
              <div style={S.grid}>
                {[["Wood",currentWand.wood],["Core",currentWand.core],["Length",currentWand.length],["Flexibility",currentWand.flex]].map(([lbl,val])=>(
                  <div key={lbl} style={S.stat}><div style={S.sLbl}>{lbl}</div><div style={S.sVal}>{val}</div></div>
                ))}
              </div>
              <div style={{marginTop:18}}>
                {screen==="success"
                  ?<button style={{...S.btn,...S.btnGreen}} onClick={confirmPurchase}>✦ Confirm Match ✦</button>
                  :isFinalFail
                  ?<button style={S.btn} onClick={tryFinalWand} disabled={isAnimating}>Try Again</button>
                  :<button style={{...S.btn,opacity:isAnimating?.5:1}} onClick={tryAgain} disabled={isAnimating}>Try Again</button>
                }
              </div>
            </>
          )}
        </div>
      )}

      {/* LABEL */}
      {screen==="label"&&finalWand&&(
        <div style={{...S.card,maxWidth:440}}>
          <div style={{textAlign:"center",marginBottom:18,marginTop:6}}>
            <div style={{color:"#d4a843",fontSize:13,letterSpacing:4,textTransform:"uppercase",textShadow:"0 0 10px rgba(212,168,67,0.5)"}}>Wand Matched!</div>
          </div>
          <ParchmentLabel wand={finalWand} name={currentName} hideNumber={freePlay}/>
          <button style={{...S.btn,marginTop:22}} onClick={backToSelect}>✦ Next Wizard ✦</button>
        </div>
      )}

      <style>{`
        @keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        button:hover{filter:brightness(1.15);}
        button:active{transform:translateY(0);}
        ::-webkit-scrollbar{width:6px;}
        ::-webkit-scrollbar-thumb{background:rgba(150,80,255,0.3);border-radius:3px;}
      `}</style>
    </div>
  );
}
